SELECT ,
    (SELECT GROUP_CONCAT(oi.product_name SEPARATOR ', ') FROM order_item oi WHERE oi.order_no = order.order_no) as product_names
FROM `order`
WHERE user_id = #{userId}

    AND status = #{status}

ORDER BY create_time DESC

    LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM `order`
WHERE user_id = #{userId}

    AND status = #{status}

SELECT order_no
FROM `order`
WHERE status = #{status}
  AND create_time < #{deadline}
LIMIT #{limit}

